 1	import type { FC } from 'react';
 2	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 3	import { PROVIDER_TYPES } from 'src/providers/utils/constants';
 4	
 5	import SectionHeading from '@components/headers/SectionHeading';
 6	import OvaFileUploader from '@components/OvaFileUploader/OvaFileUploader';
 7	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 8	import { isEmpty } from '@utils/helpers';
 9	import { useForkliftTranslation } from '@utils/i18n';
10	
11	import type { DetailsSectionProps } from './utils/types';
12	import { isApplianceManagementEnabled } from './utils/utils';
13	
14	const UploadFilesSection: FC<DetailsSectionProps> = ({ data }) => {
15	  const { t } = useForkliftTranslation();
16	
17	  const { permissions, provider } = data;
18	
19	  if (isEmpty(provider) || isEmpty(permissions))
20	    return <span className="text-muted">{t('No provider data available.')}</span>;
21	
22	  if (provider?.spec?.type !== PROVIDER_TYPES.ova) return null;
23	  if (!isApplianceManagementEnabled(provider)) return null;
24	
25	  return (
26	    <ModalHOC>
27	      <PageSection variant={PageSectionVariants.light} className="forklift-page-section--details">
28	        <SectionHeading text={t('Upload local OVA files')} />
29	        <OvaFileUploader provider={provider} />
30	      </PageSection>
31	    </ModalHOC>
32	  );
33	};
34	
35	export default UploadFilesSection;

